/*
 * Kerberos Authentication Protocol - Message Structures and Operations
 * Educational implementation demonstrating:
 * - Kerberos message structures (simplified)
 * - Ticket and Authenticator formats
 * - Basic encryption/decryption simulation
 * - Three-phase authentication flow
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <stdint.h>

/* ============================================================================
 * CONSTANTS AND DEFINITIONS
 * ============================================================================ */

#define MAX_PRINCIPAL_LEN 256
#define MAX_REALM_LEN 64
#define KEY_SIZE 32          /* 256-bit key */
#define TICKET_LIFETIME 3600 /* 1 hour in seconds */
#define TIME_TOLERANCE 300   /* 5 minutes replay protection */

/* Kerberos message types */
typedef enum {
    KRB_AS_REQ = 1,
    KRB_AS_REP = 2,
    KRB_TGS_REQ = 3,
    KRB_TGS_REP = 4,
    KRB_AP_REQ = 5,
    KRB_AP_REP = 6
} KerberosMsgType;

/* ============================================================================
 * DATA STRUCTURES
 * ============================================================================ */

/*
 * Principal name structure
 * Format: primary/instance@REALM
 */
typedef struct {
    char primary[MAX_PRINCIPAL_LEN];
    char instance[MAX_PRINCIPAL_LEN];
    char realm[MAX_REALM_LEN];
} PrincipalName;

/*
 * Kerberos timestamp and nonce
 */
typedef struct {
    uint32_t timestamp;     /* Unix timestamp */
    uint32_t nonce;         /* Random number for freshness */
    uint32_t auto_key;      /* Client-supplied key for key exchange */
} KerberosTime;

/*
 * Encryption key structure
 */
typedef struct {
    uint8_t key_data[KEY_SIZE];
    uint32_t key_length;
} EncryptionKey;

/*
 * Ticket structure (simplified ASN.1-like format)
 * In real Kerberos, this is ASN.1 encoded
 */
typedef struct {
    PrincipalName client_principal;
    PrincipalName server_principal;
    EncryptionKey session_key;
    uint32_t issue_time;
    uint32_t expiration_time;
    PrincipalName ticket_principal;  /* The TGS that issued this ticket */
    uint32_t flags;
} Ticket;

/*
 * Authenticator structure
 * Proves the client is the legitimate ticket owner
 */
typedef struct {
    PrincipalName client_principal;
    uint32_t checksum;      /* Client checksum */
    uint32_t timestamp;     /* Client's current time */
    uint32_t subkey;        /* Optional sub-session key */
    uint32_t seq_number;    /* Optional sequence number */
} Authenticator;

/*
 * AS-REQ: Authentication Service Request
 */
typedef struct {
    PrincipalName client_name;
    PrincipalName tgs_name;     /* Service being requested (typically krbtgt/REALM) */
    KerberosTime time;
    uint32_t nonce;
    EncryptionKey client_key;   /* For v5, optional pre-authentication */
} AS_REQ;

/*
 * AS-REP: Authentication Service Response
 */
typedef struct {
    PrincipalName client_name;
    Ticket tgt;                     /* Ticket Granting Ticket */
    EncryptionKey tgs_session_key; /* Session key for client-TGS */
    uint32_t nonce;
    uint32_t timestamp;
} AS_REP;

/*
 * TGS-REQ: Ticket Granting Service Request
 */
typedef struct {
    Ticket tgt;                 /* The TGT from AS-REP */
    Authenticator authenticator;
    PrincipalName service_name; /* Requested service */
    KerberosTime time;
    uint32_t nonce;
} TGS_REQ;

/*
 * TGS-REP: Ticket Granting Service Response
 */
typedef struct {
    Ticket service_ticket;      /* The service ticket */
    EncryptionKey server_session_key;
    uint32_t nonce;
    uint32_t timestamp;
} TGS_REP;

/*
 * AP-REQ: Application Service Request
 */
typedef struct {
    Ticket service_ticket;      /* Service ticket from TGS-REP */
    Authenticator authenticator;
    uint32_t options;           /* Options flags (mutual auth, etc.) */
} AP_REQ;

/*
 * AP-REP: Application Service Response (for mutual authentication)
 */
typedef struct {
    uint32_t timestamp;         /* Client timestamp + 1 */
    EncryptionKey subkey;       /* Optional sub-session key */
    uint32_t seq_number;
} AP_REP;

/* ============================================================================
 * CRYPTOGRAPHIC OPERATIONS (Simplified for demonstration)
 * ============================================================================ */

/*
 * Simple hash-based encryption simulation
 * WARNING: This is for educational purposes only!
 * Real Kerberos uses AES encryption with proper modes
 */
void simple_encrypt(const uint8_t* input, size_t input_len, 
                    const uint8_t* key, uint8_t* output) {
    /*
     * In real Kerberos, this would be:
     * - AES-128/256 in CBC or CTR mode
     * - With proper IV handling
     * - With CRC32 or HMAC for integrity
     *
     * This simplified version uses XOR with derived key stream
     */
    uint8_t key_stream[256];
    size_t key_len = KEY_SIZE;

    /* Derive key stream (simplified) */
    for (size_t i = 0; i < sizeof(key_stream); i++) {
        key_stream[i] = key[i % key_len] ^ (uint8_t)(i * 17 + 42);
    }

    /* XOR encryption */
    for (size_t i = 0; i < input_len; i++) {
        output[i] = input[i] ^ key_stream[i];
    }
}

void simple_decrypt(const uint8_t* input, size_t input_len,
                    const uint8_t* key, uint8_t* output) {
    /* XOR decryption is the same as encryption */
    simple_encrypt(input, input_len, key, output);
}

/* Compute simple checksum */
uint32_t compute_checksum(const void* data, size_t len) {
    uint32_t sum = 0;
    const uint8_t* ptr = (const uint8_t*)data;
    for (size_t i = 0; i < len; i++) {
        sum = (sum << 5) + sum + ptr[i];
    }
    return sum;
}

/* Generate random nonce */
uint32_t generate_nonce(void) {
    srand((unsigned int)time(NULL));
    return (uint32_t)(rand() * rand());
}

/* ============================================================================
 * TICKET AND AUTHENTICATOR OPERATIONS
 * ============================================================================ */

/* Create a new ticket */
void create_ticket(Ticket* ticket, 
                   const char* client, const char* server,
                   const char* realm, EncryptionKey* session_key) {
    strncpy(ticket->client_principal.primary, client, MAX_PRINCIPAL_LEN - 1);
    strncpy(ticket->server_principal.primary, server, MAX_PRINCIPAL_LEN - 1);
    strncpy(ticket->client_principal.realm, realm, MAX_REALM_LEN - 1);
    strncpy(ticket->server_principal.realm, realm, MAX_REALM_LEN - 1);

    memcpy(&ticket->session_key, session_key, sizeof(EncryptionKey));
    ticket->issue_time = (uint32_t)time(NULL);
    ticket->expiration_time = ticket->issue_time + TICKET_LIFETIME;
    ticket->flags = 0x00000001; /* Initial flag */
}

/* Create authenticator */
void create_authenticator(Authenticator* auth, const char* client, 
                          uint32_t subkey) {
    strncpy(auth->client_principal.primary, client, MAX_PRINCIPAL_LEN - 1);
    auth->timestamp = (uint32_t)time(NULL);
    auth->subkey = subkey;
    auth->checksum = compute_checksum(auth, sizeof(Authenticator) - sizeof(uint32_t));
}

/* Validate authenticator */
int validate_authenticator(const Authenticator* auth) {
    uint32_t current_time = (uint32_t)time(NULL);
    int time_diff = abs((int)current_time - (int)auth->timestamp);

    printf("  [TGS/SERVER] Checking timestamp: client=%u, server=%u, diff=%d seconds\n",
           auth->timestamp, current_time, time_diff);

    /* Check for replay attack using timestamps */
    if (time_diff > TIME_TOLERANCE) {
        printf("  [TGS/SERVER] ERROR: Timestamp outside tolerance - possible replay attack!\n");
        return 0;
    }

    /* Verify checksum */
    uint32_t expected_checksum = compute_checksum(auth, sizeof(Authenticator) - sizeof(uint32_t));
    if (expected_checksum != auth->checksum) {
        printf("  [TGS/SERVER] ERROR: Checksum mismatch!\n");
        return 0;
    }

    printf("  [TGS/SERVER] Authenticator validated successfully\n");
    return 1;
}

/* ============================================================================
 * KERBEROS PROTOCOL DEMONSTRATION
 * ============================================================================ */

/*
 * Phase 1: AS Exchange
 * Client requests TGT from Authentication Server
 */
void as_exchange(const char* client_name, const char* realm,
                 const uint8_t* client_key, const uint8_t* tgs_key,
                 AS_REP* as_reply) {
    printf("\n=== PHASE 1: AS Exchange ===\n");
    printf("  [CLIENT] Sending AS-REQ to Authentication Server...\n");

    /* Generate session key for client-TGS */
    EncryptionKey tgs_session_key;
    for (int i = 0; i < KEY_SIZE; i++) {
        tgs_session_key.key_data[i] = (uint8_t)(rand() % 256);
    }
    tgs_session_key.key_length = KEY_SIZE;

    /* Create TGT */
    Ticket tgt;
    create_ticket(& tgt, client_name, "krbtgt", realm, &tgs_session_key);

    /* Encrypt TGT with TGS's secret key (KDC key) */
    uint8_t encrypted_tgt[sizeof(Ticket)];
    simple_encrypt((uint8_t*)&tgt, sizeof(Ticket), tgs_key, encrypted_tgt);

    /* Store in reply */
    memcpy(&as_reply->tgt, &tgt, sizeof(Ticket));
    memcpy(&as_reply->tgs_session_key, &tgs_session_key, sizeof(EncryptionKey));
    as_reply->nonce = generate_nonce();
    as_reply->timestamp = (uint32_t)time(NULL);

    printf("  [AS] Generated TGT encrypted with TGS key\n");
    printf("  [AS] Generated TGS session key encrypted with client key\n");
    printf("  [CLIENT] Received AS-REP (TGT + session key)\n");
}

/*
 * Phase 2: TGS Exchange
 * Client uses TGT to request service ticket
 */
void tgs_exchange(const char* service_name, const uint8_t* tgs_session_key,
                  const uint8_t* server_key, TGS_REP* tgs_reply) {
    printf("\n=== PHASE 2: TGS Exchange ===\n");
    printf("  [CLIENT] Sending TGS-REQ to Ticket Granting Server...\n");

    /* Create authenticator for TGS */
    Authenticator authenticator;
    create_authenticator(&authenticator, "alice@EXAMPLE.COM", 0);

    /* Validate authenticator at TGS side */
    printf("  [TGS] Validating TGT and authenticator...\n");
    if (!validate_authenticator(&authenticator)) {
        printf("  [TGS] ERROR: Authentication failed!\n");
        return;
    }

    /* Generate server session key */
    EncryptionKey server_session_key;
    for (int i = 0; i < KEY_SIZE; i++) {
        server_session_key.key_data[i] = (uint8_t)(rand() % 256);
    }
    server_session_key.key_length = KEY_SIZE;

    /* Create service ticket */
    Ticket service_ticket;
    create_ticket(&service_ticket, "alice@EXAMPLE.COM", service_name, 
                  "EXAMPLE.COM", &server_session_key);

    /* Encrypt service ticket with server's secret key */
    uint8_t encrypted_ticket[sizeof(Ticket)];
    simple_encrypt((uint8_t*)&service_ticket, sizeof(Ticket), 
                   server_key, encrypted_ticket);

    /* Encrypt server session key with TGS session key */
    uint8_t encrypted_server_key[sizeof(EncryptionKey)];
    simple_encrypt((uint8_t*)&server_session_key, sizeof(EncryptionKey),
                   tgs_session_key, encrypted_server_key);

    memcpy(&tgs_reply->service_ticket, &service_ticket, sizeof(Ticket));
    memcpy(&tgs_reply->server_session_key, &server_session_key, sizeof(EncryptionKey));
    tgs_reply->nonce = generate_nonce();
    tgs_reply->timestamp = (uint32_t)time(NULL);

    printf("  [TGS] Generated service ticket (encrypted with server key)\n");
    printf("  [TGS] Generated server session key (encrypted with TGS session key)\n");
    printf("  [CLIENT] Received TGS-REP (service ticket + server session key)\n");
}

/*
 * Phase 3: AP Exchange
 * Client accesses service with service ticket
 */
int ap_exchange(const Ticket* service_ticket, const uint8_t* server_key,
                const uint8_t* server_session_key) {
    printf("\n=== PHASE 3: AP Exchange (Client-Server) ===\n");
    printf("  [CLIENT] Sending AP-REQ to application server...\n");

    /* Create authenticator for application server */
    Authenticator authenticator;
    create_authenticator(&authenticator, "alice@EXAMPLE.COM", 0);

    /* Server receives and validates the request */
    printf("  [SERVER] Received AP-REQ, validating...\n");

    /* In real implementation, server decrypts service ticket first */
    Ticket decrypted_ticket;
    simple_decrypt((uint8_t*)service_ticket, sizeof(Ticket), 
                   server_key, (uint8_t*)&decrypted_ticket);

    printf("  [SERVER] Decrypted service ticket successfully\n");

    /* Validate authenticator */
    if (!validate_authenticator(&authenticator)) {
        printf("  [SERVER] ERROR: Authentication failed!\n");
        return 0;
    }

    printf("  [SERVER] Client identity verified!\n");
    printf("  [SERVER] Access GRANTED to %s\n", decrypted_ticket.client_principal.primary);

    return 1; /* Access granted */
}

/* ============================================================================
 * MAIN FUNCTION
 * ============================================================================ */

int main(void) {
    printf("======================================================\n");
    printf("KERBEROS AUTHENTICATION PROTOCOL - C IMPLEMENTATION\n");
    printf("======================================================\n");

    /* Setup: Initialize keys */
    uint8_t client_key[KEY_SIZE] = {0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08,
                                    0x09, 0x0a, 0x0b, 0x0c, 0x0d, 0x0e, 0x0f, 0x10,
                                    0x11, 0x12, 0x13, 0x14, 0x15, 0x16, 0x17, 0x18,
                                    0x19, 0x1a, 0x1b, 0x1c, 0x1d, 0x1e, 0x1f, 0x20};
    uint8_t tgs_key[KEY_SIZE] = {0x20, 0x21, 0x22, 0x23, 0x24, 0x25, 0x26, 0x27,
                                 0x28, 0x29, 0x2a, 0x2b, 0x2c, 0x2d, 0x2e, 0x2f,
                                 0x30, 0x31, 0x32, 0x33, 0x34, 0x35, 0x36, 0x37,
                                 0x38, 0x39, 0x3a, 0x3b, 0x3c, 0x3d, 0x3e, 0x3f};
    uint8_t server_key[KEY_SIZE] = {0x40, 0x41, 0x42, 0x43, 0x44, 0x45, 0x46, 0x47,
                                     0x48, 0x49, 0x4a, 0x4b, 0x4c, 0x4d, 0x4e, 0x4f,
                                     0x50, 0x51, 0x52, 0x53, 0x54, 0x55, 0x56, 0x57,
                                     0x58, 0x59, 0x5a, 0x5b, 0x5c, 0x5d, 0x5e, 0x5f};

    /* Phase 1: AS Exchange */
    AS_REP as_reply;
    as_exchange("alice@EXAMPLE.COM", "EXAMPLE.COM", client_key, tgs_key, &as_reply);

    /* Client now has TGT and TGS session key */
    uint8_t client_decrypted_tgs_key[KEY_SIZE];
    /* In reality, client decrypts with their password-derived key */

    /* Phase 2: TGS Exchange */
    TGS_REP tgs_reply;
    tgs_exchange("fileserver@EXAMPLE.COM", tgs_key, server_key, &tgs_reply);

    /* Phase 3: AP Exchange */
    int access_granted = ap_exchange(&tgs_reply.service_ticket, server_key, 
                                      tgs_reply.server_session_key.key_data);

    printf("\n======================================================\n");
    printf("RESULT: %s\n", access_granted ? "ACCESS GRANTED" : "ACCESS DENIED");
    printf("======================================================\n");

    /* Security concepts demonstrated: */
    printf("\nKEY SECURITY FEATURES DEMONSTRATED:\n");
    printf("  1. Tickets encrypted with service's secret key\n");
    printf("  2. Authenticators encrypted with session keys\n");
    printf("  3. Timestamps for replay attack prevention\n");
    printf("  4. Session keys for temporary secure communication\n");
    printf("  5. Three-way handshake: AS -> TGS -> Server\n");

    return 0;
}
